			changeObj(str) {
				let strArr = str.split(/&/g)
				let newArr = {}
				for (let i in strArr) {
					let key = strArr[i].split('=')[0]
					let val = strArr[i].split('=')[1]
					newArr = Object.assign(newArr, {
						[key]: val
					})
				}
